import electron from "electron";
import matter from "gray-matter";
import { access, appendFile, mkdir, readdir, readFile, rename, stat, writeFile } from "node:fs/promises";
import path from "node:path";
import { ulid } from "ulid";
import {
  DEFAULT_COLUMNS,
  RELAY_SCHEMA_VERSION,
  type BoardSnapshot,
  type ClarificationQuestion,
  type ClarificationQuestionCreateInput,
  type InvalidTicket,
  type ProjectConfig,
  type ProjectSettings,
  type ProjectSummary,
  type RelayActor,
  type RelayColumn,
  type RelayEventSource,
  type RelayAuditEvent,
  type TicketCreateInput,
  type TicketDraft,
  type TicketFrontMatter,
  type TicketMoveInput,
  type TicketRecord,
  type TicketSaveInput,
  type TicketSummary
} from "../../shared/types";
import { clarificationStoreSchema, projectConfigSchema, ticketFrontMatterSchema } from "./schemas";

const { shell } = electron;

const defaultSettings = (): ProjectSettings => ({
  defaultModel: null,
  defaultApprovalPolicy: "on-request",
  defaultSandboxMode: "workspace-write",
  allowNonGitCodexRuns: false,
  ticketDraftingEnabled: true,
  codexExecutionEnabled: true
});

const nowIso = (): string => new Date().toISOString();
const projectRelayPath = (projectPath: string): string => path.join(projectPath, ".relay");
const projectConfigPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "project.json");
const ticketsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "tickets");
export const runsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "runs");
const auditLogPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "audit.jsonl");
const clarificationsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "clarifications");
const trashPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "trash");
const attachmentsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "attachments");
const backupsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "backups");

export const newId = (prefix: string): string => `${prefix}_${ulid().toLowerCase()}`;

const fileExists = async (target: string): Promise<boolean> => {
  try {
    await access(target);
    return true;
  } catch {
    return false;
  }
};

export const isGitRepository = async (projectPath: string): Promise<boolean> => fileExists(path.join(projectPath, ".git"));

const atomicWriteJson = async (target: string, value: unknown): Promise<void> => {
  await mkdir(path.dirname(target), { recursive: true });
  const tmp = `${target}.${process.pid}.tmp`;
  await writeFile(tmp, `${JSON.stringify(value, null, 2)}\n`, "utf8");
  await rename(tmp, target);
};

const atomicWriteText = async (target: string, value: string): Promise<void> => {
  await mkdir(path.dirname(target), { recursive: true });
  const tmp = `${target}.${process.pid}.tmp`;
  await writeFile(tmp, value, "utf8");
  await rename(tmp, target);
};

const appendAuditEvent = async (projectPath: string, event: Omit<RelayAuditEvent, "schemaVersion" | "timestamp">): Promise<void> => {
  const record: RelayAuditEvent = {
    schemaVersion: RELAY_SCHEMA_VERSION,
    timestamp: nowIso(),
    ...event
  };
  const target = auditLogPath(projectPath);
  await mkdir(path.dirname(target), { recursive: true });
  await appendFile(target, `${JSON.stringify(record)}\n`, "utf8");
};

const assertDirectory = async (projectPath: string): Promise<void> => {
  const info = await stat(projectPath);
  if (!info.isDirectory()) {
    throw new Error(`Project path is not a directory: ${projectPath}`);
  }
};

export const isRelayInitialized = async (projectPath: string): Promise<boolean> => fileExists(projectConfigPath(projectPath));

export const initializeProject = async (projectPath: string): Promise<ProjectConfig> => {
  const resolved = path.resolve(projectPath);
  await assertDirectory(resolved);
  const existing = await isRelayInitialized(resolved);
  if (existing) return readProjectConfig(resolved);

  const now = nowIso();
  const config: ProjectConfig = {
    schemaVersion: RELAY_SCHEMA_VERSION,
    projectId: newId("prj"),
    name: path.basename(resolved),
    createdAt: now,
    updatedAt: now,
    columns: DEFAULT_COLUMNS.map((column) => ({ ...column })),
    settings: defaultSettings()
  };

  await mkdir(ticketsPath(resolved), { recursive: true });
  await mkdir(runsPath(resolved), { recursive: true });
  await mkdir(clarificationsPath(resolved), { recursive: true });
  await mkdir(attachmentsPath(resolved), { recursive: true });
  await mkdir(backupsPath(resolved), { recursive: true });
  await atomicWriteJson(projectConfigPath(resolved), config);
  return config;
};

export const readProjectConfig = async (projectPath: string): Promise<ProjectConfig> => {
  const raw = await readFile(projectConfigPath(projectPath), "utf8");
  return projectConfigSchema.parse(JSON.parse(raw)) as ProjectConfig;
};

export const writeProjectConfig = async (projectPath: string, config: ProjectConfig): Promise<ProjectConfig> => {
  const updated = { ...config, updatedAt: nowIso() };
  await atomicWriteJson(projectConfigPath(projectPath), updated);
  return updated;
};

export const summarizeProject = async (projectPath: string, lastOpenedAt?: string): Promise<ProjectSummary> => {
  const resolved = path.resolve(projectPath);
  const exists = await fileExists(resolved);
  const healthMessages: string[] = [];
  let config: ProjectConfig | null = null;
  let relayInitialized = false;
  let activeRunCount = 0;

  if (!exists) {
    return {
      projectId: null,
      name: path.basename(resolved),
      path: resolved,
      exists: false,
      isGitRepository: false,
      relayInitialized: false,
      health: "error",
      healthMessages: ["Project folder is missing."],
      activeRunCount: 0,
      lastOpenedAt
    };
  }

  relayInitialized = await isRelayInitialized(resolved);
  const git = await isGitRepository(resolved);

  if (!relayInitialized) {
    healthMessages.push("Relay has not initialized this project yet.");
  } else {
    try {
      config = await readProjectConfig(resolved);
      const tickets = await readTickets(resolved, config.columns);
      activeRunCount = tickets.tickets.filter((ticket) => ticket.runStatus === "running" || ticket.runStatus === "blocked").length;
      if (tickets.invalidTickets.length > 0) {
        healthMessages.push(`${tickets.invalidTickets.length} ticket file(s) need attention.`);
      }
    } catch (error) {
      healthMessages.push(error instanceof Error ? error.message : "Project metadata is invalid.");
    }
  }

  if (!git) {
    healthMessages.push("This folder is not a Git repository. Codex execution is disabled by default.");
  }

  const hasError = exists && relayInitialized && !config;
  const health = hasError ? "error" : healthMessages.length > 0 ? "warning" : "ok";

  return {
    projectId: config?.projectId ?? null,
    name: config?.name ?? path.basename(resolved),
    path: resolved,
    exists,
    isGitRepository: git,
    relayInitialized,
    health,
    healthMessages,
    activeRunCount,
    lastOpenedAt
  };
};

const extractExcerpt = (markdown: string): string => {
  const text = markdown
    .replace(/^# .+$/m, "")
    .replace(/^## .+$/gm, "")
    .replace(/[-*]\s+/g, "")
    .replace(/\s+/g, " ")
    .trim();
  return text.length > 160 ? `${text.slice(0, 157)}...` : text;
};

const readTicketFile = async (filePath: string): Promise<TicketRecord> => {
  const raw = await readFile(filePath, "utf8");
  const parsed = matter(raw);
  const frontMatter = ticketFrontMatterSchema.parse(parsed.data) as TicketFrontMatter;
  return {
    frontMatter,
    markdown: parsed.content.trimStart(),
    filePath
  };
};

const readTickets = async (
  projectPath: string,
  columns: RelayColumn[]
): Promise<{ tickets: TicketSummary[]; records: TicketRecord[]; invalidTickets: InvalidTicket[] }> => {
  await mkdir(ticketsPath(projectPath), { recursive: true });
  const entries = await readdir(ticketsPath(projectPath), { withFileTypes: true });
  const validColumnIds = new Set(columns.map((column) => column.id));
  const tickets: TicketSummary[] = [];
  const records: TicketRecord[] = [];
  const invalidTickets: InvalidTicket[] = [];

  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.endsWith(".md")) continue;
    const filePath = path.join(ticketsPath(projectPath), entry.name);
    try {
      const record = await readTicketFile(filePath);
      if (!validColumnIds.has(record.frontMatter.status)) {
        invalidTickets.push({ filePath, reason: `Unknown status: ${record.frontMatter.status}` });
        continue;
      }
      records.push(record);
      tickets.push({
        ...record.frontMatter,
        excerpt: extractExcerpt(record.markdown),
        filePath
      });
    } catch (error) {
      invalidTickets.push({
        filePath,
        reason: error instanceof Error ? error.message : "Unable to parse ticket."
      });
    }
  }

  tickets.sort((a, b) => {
    if (a.status !== b.status) return a.status.localeCompare(b.status);
    return a.position - b.position;
  });

  return { tickets, records, invalidTickets };
};

import { BrowserWindow } from "electron";
import { appendFile, mkdir, readFile } from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import { execFile } from "node:child_process";
import { promisify } from "node:util";
import { Codex, type Input, type Thread, type ThreadEvent, type ThreadItem, type ThreadOptions } from "@openai/codex-sdk";
import {
  type ClarificationQuestion,
  type CodexStatus,
  type CreateDraftInput,
  type RelayCodexEvent,
  type RendererRunEvent,
  type StartRunInput,
  type TicketDraft
} from "../../shared/types";
import { extractClarificationRequest } from "./clarificationParser";
import { ticketDraftSchema } from "./schemas";
import { logError, logInfo, logWarn } from "./logger";
import {
  appendCodexHandoff,
  createClarificationQuestions,
  isGitRepository,
  newId,
  readClarificationQuestions,
  readProjectConfig,
  readTicket,
  runsPath,
  ticketMarkdownFromDraft,
  transitionTicketStatus,
  writeTicket
} from "./storage";

const execFileAsync = promisify(execFile);
const DRAFT_TIMEOUT_MS = 90_000;

type ActiveRun = {
  abortController: AbortController;
  ticketId: string;
  projectPath: string;
};

const activeRuns = new Map<string, ActiveRun>();

const nowIso = (): string => new Date().toISOString();

const codexEnv = (): Record<string, string> => {
  const env: Record<string, string> = {};
  for (const [key, value] of Object.entries(process.env)) {
    if (typeof value === "string") env[key] = value;
  }
  return env;
};

const createCodex = (): Codex => new Codex({ env: codexEnv() });

const threadOptionsForProject = async (projectPath: string): Promise<ThreadOptions> => {
  const config = await readProjectConfig(projectPath);
  const git = await isGitRepository(projectPath);
  return {
    workingDirectory: projectPath,
    model: config.settings.defaultModel ?? undefined,
    approvalPolicy: config.settings.defaultApprovalPolicy,
    sandboxMode: config.settings.defaultSandboxMode,
    skipGitRepoCheck: config.settings.allowNonGitCodexRuns || !git,
    networkAccessEnabled: false,
    webSearchMode: "disabled"
  };
};

const ticketDraftSchemaJson = {
  type: "object",
  additionalProperties: false,
  required: [
    "title",
    "priority",
    "labels",
    "context",
    "requirements",
    "acceptanceCriteria",
    "clarificationQuestions",
    "implementationNotes"
  ],
  properties: {
    title: { type: "string" },
    priority: { type: "string", enum: ["low", "medium", "high", "urgent"] },
    labels: { type: "array", items: { type: "string" } },
    context: { type: "string" },
    requirements: { type: "array", items: { type: "string" } },
    acceptanceCriteria: { type: "array", items: { type: "string" } },
    clarificationQuestions: { type: "array", items: { type: "string" } },
    implementationNotes: { type: "array", items: { type: "string" } }
  }
} as const;

const parseJsonResponse = (value: string): unknown => {
  try {
    return JSON.parse(value);
  } catch {
    const first = value.indexOf("{");
    const last = value.lastIndexOf("}");
    if (first >= 0 && last > first) {
      return JSON.parse(value.slice(first, last + 1));
    }
    throw new Error("Codex did not return valid JSON.");
  }
};

export const getCodexStatus = async (): Promise<CodexStatus> => {
  let cliAvailable = false;
  let cliVersion: string | null = null;
  try {
    const { stdout } = await execFileAsync("codex", ["--version"], { timeout: 5000 });
    cliAvailable = true;
    cliVersion = stdout.trim();
  } catch {
    cliAvailable = false;
  }

  let authenticated: boolean | null = null;
  const hasApiKey = Boolean(process.env.OPENAI_API_KEY || process.env.CODEX_API_KEY);
  try {
    await readFile(path.join(os.homedir(), ".codex", "auth.json"), "utf8");
    authenticated = true;
  } catch {
    authenticated = hasApiKey ? true : false;
  }

  return {
    sdkAvailable: true,
    cliAvailable,
    cliVersion,
    authenticated,
    message: cliAvailable
      ? authenticated === true
        ? "Codex is available."
        : "Codex CLI is available, but no Codex auth file or API key was found."
      : "Codex CLI was not found on PATH."
  };
};

export const createTicketDraft = async ({ projectPath, idea }: CreateDraftInput): Promise<TicketDraft> => {
  await logInfo("codex:draft", "starting ticket draft", { projectPath, ideaLength: idea.length });
  const status = await getCodexStatus();
  if (!status.cliAvailable) {
    await logWarn("codex:draft", "codex cli unavailable", status);
    throw new Error("Codex CLI was not found on PATH. Install or expose Codex before drafting tickets.");
  }
  if (status.authenticated === false) {
    await logWarn("codex:draft", "codex auth unavailable", status);
    throw new Error("Codex is not authenticated. Run `codex login` in your terminal, then try drafting again.");
  }

  const config = await readProjectConfig(projectPath);
  const codex = createCodex();
  const thread = codex.startThread(await threadOptionsForProject(projectPath));
  const abortController = new AbortController();
  const timeout = setTimeout(() => abortController.abort(), DRAFT_TIMEOUT_MS);
  timeout.unref?.();
  const prompt = `You are helping create a local software implementation ticket for Relay.

The user will provide a rough idea. Convert it into a clear, actionable ticket for a coding agent and human developer.

Return only data matching the requested schema. Do not implement the task.

Project path: ${projectPath}
Project name: ${config.name}
Current board columns: ${config.columns.map((column) => column.name).join(", ")}

User idea:
${idea}`;

  try {
    const turn = await thread.run(prompt, { outputSchema: ticketDraftSchemaJson, signal: abortController.signal });
    const parsed = ticketDraftSchema.parse(parseJsonResponse(turn.finalResponse)) as TicketDraft;
    await logInfo("codex:draft", "ticket draft completed", { projectPath, title: parsed.title });
    return parsed;
  } catch (error) {
    await logError("codex:draft", abortController.signal.aborted ? "ticket draft timed out" : "ticket draft failed", error);
    if (abortController.signal.aborted) {
      throw new Error("Codex ticket drafting timed out after 90 seconds. You can save a manual ticket and try Codex again later.");
    }
    throw error;
  } finally {
    clearTimeout(timeout);
  }
};

const writeRunLog = async (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> => {
  const filePath = path.join(runsPath(projectPath), ticketId, `${runId}.jsonl`);
  await mkdir(path.dirname(filePath), { recursive: true });
  const { type, timestamp, ...payload } = event;
  await appendFile(
    filePath,
    `${JSON.stringify({
      schemaVersion: 1,
      timestamp,
      ticketId,
      runId,
      threadId,
      type,
      payload
    })}\n`,
    "utf8"
  );
};

const emitRunEvent = async (
  browserWindow: BrowserWindow,
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> => {
  await writeRunLog(projectPath, ticketId, runId, threadId, event);
  const rendererEvent: RendererRunEvent = {
    ...event,
    projectPath,
    ticketId,
    runId
  };
  browserWindow.webContents.send("codex:runEvent", rendererEvent);
};

const finalTextFromItem = (item: ThreadItem): string | null => {
  if (item.type === "agent_message") return item.text;
  if (item.type === "error") return item.message;
  if (item.type === "reasoning") return item.text;
  return null;
};

const normalizeItemEvent = (
  event: Extract<ThreadEvent, { type: "item.started" | "item.updated" | "item.completed" }>,
  outputOffsets: Map<string, number>
): RelayCodexEvent[] => {
  const timestamp = nowIso();
  const item = event.item;

  if (item.type === "agent_message") {
    const text = item.text ?? "";
    return event.type === "item.completed"
      ? [{ type: "agent.message.completed", text, timestamp }]
      : [{ type: "agent.message.delta", text, timestamp }];
  }

  if (item.type === "reasoning" && item.text) {
    return [{ type: "agent.message.delta", text: item.text, timestamp }];
  }

  if (item.type === "command_execution") {
    const normalized: RelayCodexEvent[] = [];
    if (event.type === "item.started") {
      normalized.push({ type: "command.started", command: item.command, timestamp });
    }
    const offset = outputOffsets.get(item.id) ?? 0;
    const output = item.aggregated_output ?? "";
    if (output.length > offset) {
      normalized.push({ type: "command.output", stream: "stdout", text: output.slice(offset), timestamp });
      outputOffsets.set(item.id, output.length);
    }
    if (event.type === "item.completed") {
      normalized.push({
        type: "command.completed",
        status: item.status === "completed" ? "completed" : "failed",
        timestamp
      });
    }
    return normalized;
  }

  if (item.type === "file_change" && event.type === "item.completed") {
    return item.changes.map((change) => ({
      type: "file.change",
      path: change.path,
      summary: `${change.kind} ${change.path}`,
      timestamp
    }));
  }

  if (item.type === "error") {
    return [{ type: "run.failed", message: item.message, timestamp }];
  }

  if (item.type === "mcp_tool_call") {
    return [
      {
        type: "agent.message.delta",
        text: `${item.server}.${item.tool} ${item.status}`,
        timestamp
      }
    ];
  }

  if (item.type === "web_search") {
    return [{ type: "agent.message.delta", text: `Web search: ${item.query}`, timestamp }];
  }

  return [];
};

const formatClarificationsForPrompt = (clarifications: ClarificationQuestion[]): string => {
  if (clarifications.length === 0) return "No clarification questions have been recorded for this ticket.";
  return clarifications
    .map((question) => {
      const status = question.answer ? "answered" : "unanswered";
      const answer = question.answer ? `\nAnswer: ${question.answer}` : "";
      return `- [${status}] ${question.question}${answer}`;
    })
    .join("\n");
};

const buildExecutionPrompt = (ticketMarkdown: string, clarifications: ClarificationQuestion[]): string => `You are working inside the local project folder for this Relay ticket.

Follow the ticket exactly. Ask for clarification if the ticket is missing a required product or implementation decision.

Clarification records already attached to this ticket:
${formatClarificationsForPrompt(clarifications)}

If you cannot continue without user input, stop work and include a fenced relay-clarification JSON block in your final response.
The block must use this shape:
\`\`\`relay-clarification
{"questions":[{"question":"The specific question for the user"}]}
\`\`\`

Do not mark the ticket completed yourself. At the end, provide:
- Summary of changes made
- Files changed
- Commands run
- Tests run and their results
- Any remaining risks or follow-up work

Ticket:
${ticketMarkdown}`;

const updateTicketRunState = async (
  projectPath: string,
  ticketId: string,
  patch: Partial<{
    codexThreadId: string | null;
    runStatus: "idle" | "drafting" | "running" | "blocked" | "failed" | "completed" | "cancelled";
    lastRunId: string | null;
    status: string;
    markdown: string;
  }>
): Promise<void> => {
  const ticket = await readTicket(projectPath, ticketId);
  await writeTicket(projectPath, {
    ...ticket,
    markdown: patch.markdown ?? ticket.markdown,
    frontMatter: {
      ...ticket.frontMatter,
      codexThreadId: patch.codexThreadId !== undefined ? patch.codexThreadId : ticket.frontMatter.codexThreadId,
      runStatus: patch.runStatus ?? ticket.frontMatter.runStatus,
      lastRunId: patch.lastRunId !== undefined ? patch.lastRunId : ticket.frontMatter.lastRunId,
      status: patch.status ?? ticket.frontMatter.status
    }
  });
};

const beginRun = async (
  browserWindow: BrowserWindow,
  input: StartRunInput,
  resume: boolean
): Promise<{ runId: string; threadId: string }> => {
  await logInfo("codex:run", "starting run", { projectPath: input.projectPath, ticketId: input.ticketId, resume, freshThread: input.freshThread });
  const config = await readProjectConfig(input.projectPath);
  if (!config.settings.codexExecutionEnabled) {
    throw new Error("Codex execution is disabled for this project.");
  }

  const git = await isGitRepository(input.projectPath);
  if (!git && !config.settings.allowNonGitCodexRuns) {
    throw new Error("This project is not a Git repository. Enable non-Git Codex runs in project settings first.");
  }

  const ticket = await readTicket(input.projectPath, input.ticketId);
  if (ticket.frontMatter.status === "not_doing") {
    throw new Error("Move this ticket out of Not Doing before starting Codex.");
  }

  const clarifications = await readClarificationQuestions(input.projectPath, input.ticketId);
  const codex = createCodex();
  const options = await threadOptionsForProject(input.projectPath);
  const runId = newId("run");
  const existingThreadId = resume && !input.freshThread ? ticket.frontMatter.codexThreadId : null;
  const thread: Thread = existingThreadId ? codex.resumeThread(existingThreadId, options) : codex.startThread(options);
  const abortController = new AbortController();
  const prompt = buildExecutionPrompt(ticket.markdown, clarifications);
  const outputOffsets = new Map<string, number>();
  activeRuns.set(runId, {
    abortController,
    ticketId: input.ticketId,
    projectPath: input.projectPath
  });

  const status = config.columns.some((column) => column.id === "in_progress") ? "in_progress" : ticket.frontMatter.status;
  await updateTicketRunState(input.projectPath, input.ticketId, {
    runStatus: "running",
    lastRunId: runId
  });
  await transitionTicketStatus(input.projectPath, input.ticketId, status, {
    actor: "codex",
    source: "agent_execution",
    runId
  });

  let currentThreadId = existingThreadId ?? thread.id ?? `pending_${runId}`;
  const streamed = await thread.runStreamed(prompt, { signal: abortController.signal });
  const started = new Promise<{ runId: string; threadId: string }>((resolve) => {
    let resolved = false;
    const resolveOnce = (threadId: string): void => {
      if (!resolved) {
        resolved = true;
        resolve({ runId, threadId });
      }
    };

    void (async () => {
      let finalResponse = "";
      try {
        if (existingThreadId) {
          await emitRunEvent(browserWindow, input.projectPath, input.ticketId, runId, currentThreadId, {
            type: "run.started",
            runId,
            threadId: currentThreadId,
            timestamp: nowIso()
          });
          resolveOnce(currentThreadId);
        }

        for await (const event of streamed.events) {
          if (event.type === "thread.started") {
            currentThreadId = event.thread_id;
            await updateTicketRunState(input.projectPath, input.ticketId, {
              codexThreadId: currentThreadId,
              runStatus: "running",
              lastRunId: runId
            });
            await emitRunEvent(browserWindow, input.projectPath, input.ticketId, runId, currentThreadId, {
              type: "run.started",
              runId,
              threadId: currentThreadId,
              timestamp: nowIso()
            });
            resolveOnce(currentThreadId);
            continue;
          }

          if (event.type === "item.started" || event.type === "item.updated" || event.type === "item.completed") {
            const text = finalTextFromItem(event.item);
            if (event.item.type === "agent_message" && text) finalResponse = text;
            const normalized = normalizeItemEvent(event, outputOffsets);
            for (const relayEvent of normalized) {
              await emitRunEvent(browserWindow, input.projectPath, input.ticketId, runId, currentThreadId, relayEvent);
            }
            continue;
          }

          if (event.type === "turn.failed" || event.type === "error") {
            const message = event.type === "turn.failed" ? event.error.message : event.message;
            await updateTicketRunState(input.projectPath, input.ticketId, { runStatus: "failed" });
